#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e5+5;
int n,m,maxx=-1,a[maxn],s[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for (int i=1; i<=n; i++) {
		cin>>a[i];
		a[i]*=10000;
		maxx=max(maxx,a[i]);
	}
	int l=0,r=maxx;
	while (l<=r) {
		int kxx=0,mid=l+r>>1,minn=0;
		for (int i=1; i<=n; i++) {
			s[i]=s[i-1]+(a[i]-mid);
			if (i>=m) {
				minn=min(minn,s[i-m]);
				if (s[i]>minn) {
					kxx=1;
					break;
				}
			}
		}
		if (kxx) {
			l=mid+1;
		} else {
			r=mid-1;
		}
	}
	cout<<l/10;
	return 0;
}
